// A5: builds each deliverable from the decoded, citation-carrying JSON
// only -- never raw guesswork. One inference call per component,
// serialized (AI concurrency=1, A14).

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const doc = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'project_document.json'), 'utf8'));
const tierMap = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'tier_map.json'), 'utf8'));

const components = [
  { key: 'compliance_checklist', label: 'Compliance checklist & requirements review' },
  { key: 'end_to_end_drafting', label: 'End-to-end proposal drafting' },
  { key: 'sow_budget', label: 'SOW draft and budget template' }
];

return components.map(c => ({
  json: {
    project_prefix: prefix,
    component_key: c.key,
    component_label: c.label,
    decoded_facts: doc.decoded_facts,
    tier_map: tierMap
  }
}));

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const key = $json.component_key;
const outDir = path.join('Working', prefix, 'master_set');
fs.mkdirSync(outDir, { recursive: true });

// exceljs formula-liveness applies only to the compliance checklist,
// where scored items must be live formulas, not typed values (A5).
// That specific spreadsheet build step lives in its own node below
// when component_key === 'compliance_checklist'; other components
// write as .md, which is the standard for text deliverables (B5).

fs.writeFileSync(path.join(outDir, key + '.md'), $json.response || '', 'utf8');

return [{ json: { project_prefix: prefix, component_key: key, written: true } }];
